import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.Bk_3gXAz.js";const u=JSON.parse('{"title":"Vibe Coding Guide for Non-Coders","description":"A complete guide to Vibe Coding with CodyMaster — no programming knowledge required.","frontmatter":{"title":"Vibe Coding Guide for Non-Coders","description":"A complete guide to Vibe Coding with CodyMaster — no programming knowledge required.","keywords":["vibe coding","no-code","ai agent","codymaster","tutorial"],"robots":"index, follow"},"headers":[],"relativePath":"brainstorm/codegraph-viewer.md","filePath":"brainstorm/codegraph-viewer.md"}'),s={name:"brainstorm/codegraph-viewer.md"};function n(r,e,l,d,h,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="vibe-coding-guide-for-non-coders" tabindex="-1">Vibe Coding Guide for Non-Coders <a class="header-anchor" href="#vibe-coding-guide-for-non-coders" aria-label="Permalink to &quot;Vibe Coding Guide for Non-Coders&quot;">​</a></h1><blockquote><p><strong>Vibe Coding</strong> = You talk, AI codes. No programming knowledge required.<br> This documentation is for non-developers — founders, PMs, marketers, designers — who want to use AI to build real products.</p></blockquote><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#what-is-vibe-coding">What is Vibe Coding?</a></li><li><a href="#what-do-you-need-to-prepare">What do you need to prepare?</a></li><li><a href="#installing-codymaster-5-minutes">Installing CodyMaster (5 minutes)</a></li><li><a href="#5-step-workflow">5-Step Workflow</a></li><li><a href="#10-sample-prompts-copy-use-instantly">10 Sample Prompts — Copy &amp; Use Instantly</a></li><li><a href="#tips-for-effective-vibe-coding">Tips for Effective Vibe Coding</a></li><li><a href="#common-mistakes">Common Mistakes</a></li><li><a href="#frequently-asked-questions-faq">Frequently Asked Questions (FAQ)</a></li></ol><hr><h2 id="what-is-vibe-coding" tabindex="-1">What is Vibe Coding? <a class="header-anchor" href="#what-is-vibe-coding" aria-label="Permalink to &quot;What is Vibe Coding?&quot;">​</a></h2><p><strong>Vibe Coding</strong> is a method of creating products by <strong>talking to AI</strong>. You describe your ideas in natural language (Vietnamese works perfectly fine), and the AI will:</p><ul><li>📋 Plan in detail</li><li>🎨 Design the interface</li><li>💻 Write the source code</li><li>🧪 Run tests to ensure no bugs</li><li>🚀 Deploy the product to the internet</li></ul><p>You don&#39;t need to touch a single line of code. Your job is to <strong>&quot;Vibe&quot;</strong> — maintain the vision, give feedback, and direct the AI.</p><hr><h2 id="what-do-you-need-to-prepare" tabindex="-1">What do you need to prepare? <a class="header-anchor" href="#what-do-you-need-to-prepare" aria-label="Permalink to &quot;What do you need to prepare?&quot;">​</a></h2><ol><li><strong>A clear idea:</strong> What do you want to build? (e.g., A landing page for a coffee shop, a personal financial management app).</li><li><strong>An AI Agent:</strong> We recommend using <strong>Cursor</strong> (an AI-powered code editor) or <strong>Claude Code</strong> (a command-line tool).</li><li><strong>CodyMaster Kit:</strong> This is the &quot;brain&quot; that helps AI work professionally, write clean code, and avoid common mistakes.</li></ol><hr><h2 id="installing-codymaster-5-minutes" tabindex="-1">Installing CodyMaster (5 minutes) <a class="header-anchor" href="#installing-codymaster-5-minutes" aria-label="Permalink to &quot;Installing CodyMaster (5 minutes)&quot;">​</a></h2><h3 id="method-1-use-the-installer-recommended" tabindex="-1">Method 1: Use the installer (Recommended) <a class="header-anchor" href="#method-1-use-the-installer-recommended" aria-label="Permalink to &quot;Method 1: Use the installer (Recommended)&quot;">​</a></h3><p>Open the Terminal (on Mac) or Command Prompt (on Windows) and type:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @tody-agent/codymaster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The <code>codymaster</code> command will open a menu to choose your AI Agent (Cursor, Claude, Gemini...) and automatically install everything for you.</p><h3 id="method-2-automatic-installation-via-script" tabindex="-1">Method 2: Automatic installation via Script <a class="header-anchor" href="#method-2-automatic-installation-via-script" aria-label="Permalink to &quot;Method 2: Automatic installation via Script&quot;">​</a></h3><p>If your machine doesn&#39;t have npm, use the following command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/tody-agent/codymaster/main/install.sh)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This command automatically detects and installs CodyMaster for all AI agents on your machine.</p><h3 id="method-3-manual-installation-for-each-agent" tabindex="-1">Method 3: Manual installation for each agent <a class="header-anchor" href="#method-3-manual-installation-for-each-agent" aria-label="Permalink to &quot;Method 3: Manual installation for each agent&quot;">​</a></h3><p><strong>Cursor IDE:</strong> Copy the <code>skills/</code> folder into the <code>.cursor/rules/</code> directory of your project.</p><p><strong>Claude Code:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cm@codymaster</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Gemini Antigravity:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/tody-agent/codymaster/main/install.sh)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --antigravity</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="_5-step-workflow" tabindex="-1">5-Step Workflow <a class="header-anchor" href="#_5-step-workflow" aria-label="Permalink to &quot;5-Step Workflow&quot;">​</a></h2><h3 id="step-1-💡-describe-your-idea-the-prompt" tabindex="-1">Step 1: 💡 Describe your idea (The Prompt) <a class="header-anchor" href="#step-1-💡-describe-your-idea-the-prompt" aria-label="Permalink to &quot;Step 1: 💡 Describe your idea (The Prompt)&quot;">​</a></h3><p>Talk to the AI agent as if you were talking to a senior developer.</p><p><strong>Example:</strong></p><blockquote><p>&quot;I want to create a landing page for my premium spa brand. It needs a booking form, a photo gallery, and a customer reviews section.&quot;</p></blockquote><p><strong>Tip:</strong> Be as specific as possible. State clearly:</p><ul><li>Brand name</li><li>Style/tone (luxury, playful, professional...)</li><li>Required features</li><li>Preferred colors (if any)</li></ul><h3 id="step-2-📋-ai-analysis-planning" tabindex="-1">Step 2: 📋 AI Analysis &amp; Planning <a class="header-anchor" href="#step-2-📋-ai-analysis-planning" aria-label="Permalink to &quot;Step 2: 📋 AI Analysis &amp; Planning&quot;">​</a></h3><p>CodyMaster will:</p><ol><li>Analyze your requirements</li><li>Ask for more information if something is missing</li><li>Write an <code>implementation_plan.md</code> — a detailed plan</li></ol><p><strong>⚠️ IMPORTANT:</strong> AI will ask you to approve the plan before coding. <strong>READ IT CAREFULLY</strong> and give feedback! This is your most important &quot;direction&quot; moment.</p><h3 id="step-3-🎨-ai-interface-design" tabindex="-1">Step 3: 🎨 AI Interface Design <a class="header-anchor" href="#step-3-🎨-ai-interface-design" aria-label="Permalink to &quot;Step 3: 🎨 AI Interface Design&quot;">​</a></h3><p>CodyMaster automatically:</p><ul><li>Chooses appropriate fonts and colors</li><li>Applies 48 UX rules (Fitts&#39;s Law, Hick&#39;s Law, etc.)</li><li>Creates a preview for you to see</li></ul><p>You review and say: &quot;Okay&quot; or &quot;Make the font bigger, add a CTA button at the end.&quot;</p><h3 id="step-4-💻-ai-coding-testing" tabindex="-1">Step 4: 💻 AI Coding &amp; Testing <a class="header-anchor" href="#step-4-💻-ai-coding-testing" aria-label="Permalink to &quot;Step 4: 💻 AI Coding &amp; Testing&quot;">​</a></h3><p>CodyMaster writes code with full:</p><ul><li>✅ Automated tests (test first, code later — TDD)</li><li>✅ Security scans (no leaked secret keys, passwords)</li><li>✅ Automated bug checks</li></ul><p>You <strong>don&#39;t need to read the code</strong>. If the AI encounters an error, CodyMaster will tell it how to fix it itself.</p><h3 id="step-5-🚀-one-click-deploy" tabindex="-1">Step 5: 🚀 One-Click Deploy <a class="header-anchor" href="#step-5-🚀-one-click-deploy" aria-label="Permalink to &quot;Step 5: 🚀 One-Click Deploy&quot;">​</a></h3><p>Once you are satisfied, say:</p><blockquote><p>&quot;Deploy this to the internet.&quot;</p></blockquote><p>CodyMaster runs the 8-gate &quot;Safe Deploy&quot; pipeline: <code>Gate 1: Secrets → Gate 2: Syntax → Gate 3: Tests → Gate 4: i18n → Gate 5: Build → Gate 6: Smoke test → Gate 7: Deploy → Gate 8: Verify live</code></p><p>All gates pass → your product is automatically live on the internet! 🎉</p><hr><h2 id="_10-sample-prompts" tabindex="-1">10 Sample Prompts <a class="header-anchor" href="#_10-sample-prompts" aria-label="Permalink to &quot;10 Sample Prompts&quot;">​</a></h2><p>Copy &amp; paste these prompts into your AI agent to get started right away:</p><h3 id="_1-🌐-create-a-landing-page" tabindex="-1">1. 🌐 Create a Landing Page <a class="header-anchor" href="#_1-🌐-create-a-landing-page" aria-label="Permalink to &quot;1. 🌐 Create a Landing Page&quot;">​</a></h3><blockquote><p>Create a landing page for the brand [NAME]. Industry [INDUSTRY]. Tone [STYLE]. Needs: hero section, introduction, pricing table, testimonials, contact form, and footer. Deploy immediately.</p></blockquote><h3 id="_2-📊-management-dashboard" tabindex="-1">2. 📊 Management Dashboard <a class="header-anchor" href="#_2-📊-management-dashboard" aria-label="Permalink to &quot;2. 📊 Management Dashboard&quot;">​</a></h3><blockquote><p>Create a management dashboard for [DATA TYPE] for [BUSINESS TYPE]. Needs revenue charts by day/month, a list table of [ITEMS], and filters by time period.</p></blockquote><h3 id="_3-📱-booking-system" tabindex="-1">3. 📱 Booking System <a class="header-anchor" href="#_3-📱-booking-system" aria-label="Permalink to &quot;3. 📱 Booking System&quot;">​</a></h3><blockquote><p>Create a booking system for [SERVICE TYPE]. Customers choose a service → choose date/time → enter information → confirm. Send email reminder 24h before.</p></blockquote><h3 id="_4-🛒-sales-page" tabindex="-1">4. 🛒 Sales Page <a class="header-anchor" href="#_4-🛒-sales-page" aria-label="Permalink to &quot;4. 🛒 Sales Page&quot;">​</a></h3><blockquote><p>Create a sales page for the product [PRODUCT NAME]. Needs: product photos, description, price, buy button, FAQ, social proof, and Zalo/Messenger buttons.</p></blockquote><h3 id="_5-✍️-blog-content" tabindex="-1">5. ✍️ Blog &amp; Content <a class="header-anchor" href="#_5-✍️-blog-content" aria-label="Permalink to &quot;5. ✍️ Blog &amp; Content&quot;">​</a></h3><blockquote><p>Create a blog for brand [NAME] in the field of [FIELD]. Write the first 5 articles about [TOPIC]. SEO optimized.</p></blockquote><h3 id="_6-🔐-member-portal" tabindex="-1">6. 🔐 Member Portal <a class="header-anchor" href="#_6-🔐-member-portal" aria-label="Permalink to &quot;6. 🔐 Member Portal&quot;">​</a></h3><blockquote><p>Build a member portal where users can register, log in, and see content reserved for [MEMBERSHIP LEVEL]. Use Supabase for authentication.</p></blockquote><h3 id="_7-🤖-custom-ai-bot" tabindex="-1">7. 🤖 Custom AI Bot <a class="header-anchor" href="#_7-🤖-custom-ai-bot" aria-label="Permalink to &quot;7. 🤖 Custom AI Bot&quot;">​</a></h3><blockquote><p>Create a web interface for an AI chatbot specializing in [EXPERTISE]. Use the OpenAI API. Needs chat history and a &quot;Clear Chat&quot; button.</p></blockquote><h3 id="_8-📅-event-page" tabindex="-1">8. 📅 Event Page <a class="header-anchor" href="#_8-📅-event-page" aria-label="Permalink to &quot;8. 📅 Event Page&quot;">​</a></h3><blockquote><p>Create a registration page for the event [EVENT NAME]. Needs a countdown timer, speakers list, agenda, and a &quot;Register Now&quot; button that saves data to a Google Sheet.</p></blockquote><h3 id="_9-🎨-portfolio" tabindex="-1">9. 🎨 Portfolio <a class="header-anchor" href="#_9-🎨-portfolio" aria-label="Permalink to &quot;9. 🎨 Portfolio&quot;">​</a></h3><blockquote><p>Create a portfolio for a [PROFESSION]. Needs a project gallery with filter by category, an &quot;About Me&quot; section, and a contact form. Minimalist style.</p></blockquote><h3 id="_10-🛠️-internal-tool" tabindex="-1">10. 🛠️ Internal Tool <a class="header-anchor" href="#_10-🛠️-internal-tool" aria-label="Permalink to &quot;10. 🛠️ Internal Tool&quot;">​</a></h3><blockquote><p>Build a tool for the team to [TASK NAME]. Needs to connect to [API/DATABASE] and allow users to search, edit, and export data to Excel.</p></blockquote><hr><h2 id="tips-for-effective-vibe-coding" tabindex="-1">Tips for Effective Vibe Coding <a class="header-anchor" href="#tips-for-effective-vibe-coding" aria-label="Permalink to &quot;Tips for Effective Vibe Coding&quot;">​</a></h2><ol><li><strong>Start Small:</strong> Don&#39;t try to build &quot;Facebook&quot; in one day. Build one core feature first, then expand.</li><li><strong>The &quot;Approved&quot; Rule:</strong> Never let AI code until you have read and approved the <code>implementation_plan.md</code>.</li><li><strong>Use the Dashboard:</strong> Run <code>cm dashboard</code> to see the work progress visually.</li><li><strong>Don&#39;t Be Afraid to Reject:</strong> If the design is ugly, say it&#39;s ugly. AI doesn&#39;t have feelings — tell it exactly what you want to change.</li><li><strong>Continuous Continuity:</strong> Use <code>cm continuity status</code> to ensure the AI remembers what it was doing from the previous session.</li></ol><hr><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><ul><li><strong>Vague prompts:</strong> &quot;Build me a website&quot; → AI won&#39;t know what you want.</li><li><strong>Skipping tests:</strong> &quot;Code it fast, no need for tests&quot; → You will get bugs later.</li><li><strong>Not reading the plan:</strong> This is the #1 cause of AI &quot;going off track.&quot;</li><li><strong>Over-complicating:</strong> Trying to add too many features at once makes the AI confused.</li></ul><hr><h2 id="frequently-asked-questions-faq" tabindex="-1">Frequently Asked Questions (FAQ) <a class="header-anchor" href="#frequently-asked-questions-faq" aria-label="Permalink to &quot;Frequently Asked Questions (FAQ)&quot;">​</a></h2><p><strong>Q: Do I really not need to know any code?</strong> A: Correct. But you need to know &quot;Logic.&quot; You need to be able to describe how the app should work.</p><p><strong>Q: Is it expensive?</strong> A: You only pay for the AI API (OpenAI/Claude) which is usually a few dollars for a small project. CodyMaster is free and open source.</p><p><strong>Q: Can I build mobile apps?</strong> A: Yes. You can build web apps that work perfectly on mobile or use Flutter/React Native to build native apps.</p><p><strong>Q: What if the AI gets stuck?</strong> A: Use the <code>cm-debugging</code> skill. It will help the AI analyze why it&#39;s stuck and find a way out.</p><hr><blockquote><p><strong>&quot;A non-coder&#39;s most painful lesson is a sleepless night.<br> And now, you don&#39;t have to go through those nights.&quot;</strong><br> — Tody Le, Creator of CodyMaster</p></blockquote><hr><p><em>This documentation is part of the <a href="https://github.com/tody-agent/codymaster" target="_blank" rel="noreferrer">CodyMaster Kit</a> — Free &amp; Open Source.</em></p>',93)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
